import { Test, TestingModule } from '@nestjs/testing';
import { JwtService } from '@nestjs/jwt';
import { AuthService } from './auth.service';
import { UnauthorizedException } from '@nestjs/common';

describe('AuthService', () => {
  let service: AuthService;
  let jwtService: JwtService;

  const mockJwtService = {
    signAsync: jest.fn(),
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AuthService,
        { provide: JwtService, useValue: mockJwtService },
      ],
    }).compile();

    service = module.get<AuthService>(AuthService);
    jwtService = module.get<JwtService>(JwtService);
  });

  it('devrait retourner un token pour des identifiants valides', async () => {
    mockJwtService.signAsync.mockResolvedValue('jwt_token_123');

    const result = await service.login('user@example.com', 'password123');

    expect(result).toEqual({ access_token: 'jwt_token_123' });
    expect(mockJwtService.signAsync).toHaveBeenCalledWith({
      sub: 1,
      email: 'user@example.com',
    });
  });

  it('devrait lancer une exception pour des identifiants invalides', async () => {
    await expect(
      service.login('wrong@example.com', 'wrongpass')
    ).rejects.toThrow(UnauthorizedException);

    expect(mockJwtService.signAsync).not.toHaveBeenCalled();
  });
});
